import{_ as t,o as i,c as l,ae as e}from"./chunks/framework.EHGTsUvI.js";const u=JSON.parse('{"title":"代码库上下文工程：让 AI 真正理解你的项目","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/context-prompting.md","filePath":"ai-tutorial/context-prompting.md"}'),s={name:"ai-tutorial/context-prompting.md"};function r(n,a,o,p,d,h){return i(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="代码库上下文工程-让-ai-真正理解你的项目" tabindex="-1">代码库上下文工程：让 AI 真正理解你的项目 <a class="header-anchor" href="#代码库上下文工程-让-ai-真正理解你的项目" aria-label="Permalink to &quot;代码库上下文工程：让 AI 真正理解你的项目&quot;">​</a></h1><blockquote><p>代码场景里，最让人挫败的一幕不是模型不会写，而是它明明写得很像样，放进项目里却怎么看都别扭。 它可能语法没错、命名也像回事，但就是和你的工程上下文对不上：它不知道这段代码在整个系统里扮演什么角色，不知道哪个类其实只是过渡层，也不知道你们团队到底把什么当成“合理做法”。 所以在代码场景中，真正决定输出质量的往往不是那一句 Prompt 本身，而是你到底喂给了模型多少“项目里的现实”。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>为什么代码场景下的 Prompt 问题，本质上是上下文工程问题</li><li>什么叫“局部上下文、仓库上下文、任务上下文、反馈上下文”</li><li>IDE、索引、检索、压缩和摘要各自解决什么问题</li><li>如何在成本、延迟与质量之间取得平衡</li></ul></div><h2 id="_1-最常见的问题-模型知道语法-不知道项目" tabindex="-1">1. 最常见的问题：模型知道语法，不知道项目 <a class="header-anchor" href="#_1-最常见的问题-模型知道语法-不知道项目" aria-label="Permalink to &quot;1. 最常见的问题：模型知道语法，不知道项目&quot;">​</a></h2><p>模型通常具备不错的语言和代码生成能力，但它天然不知道：</p><ul><li>你的模块边界</li><li>业务命名约定</li><li>哪些类是基础设施，哪些类是核心领域</li><li>你的构建系统、测试策略和回滚方式</li></ul><p>这解释了为什么很多“单文件改动建议”看起来语法没错，但放到项目里就是不成立：</p><ul><li>改动漏掉了接口实现</li><li>只改调用方，没改契约</li><li>生成了团队根本不用的模式</li><li>修了表面报错，却破坏了隐藏分支</li></ul><p>换句话说，代码场景里真正稀缺的不是模型的“语言能力”，而是<strong>高质量上下文</strong>。</p><h2 id="_2-上下文不是一段长-prompt-而是一个分层系统" tabindex="-1">2. 上下文不是一段长 Prompt，而是一个分层系统 <a class="header-anchor" href="#_2-上下文不是一段长-prompt-而是一个分层系统" aria-label="Permalink to &quot;2. 上下文不是一段长 Prompt，而是一个分层系统&quot;">​</a></h2><p>可以把代码场景下的上下文分成四层：</p><table tabindex="0"><thead><tr><th>层次</th><th>内容</th><th>作用</th></tr></thead><tbody><tr><td>局部上下文</td><td>当前文件、附近代码、选中片段</td><td>解决眼前改动</td></tr><tr><td>仓库上下文</td><td>相关接口、调用链、相邻模块、项目约定</td><td>解决“改动会不会影响别处”</td></tr><tr><td>任务上下文</td><td>当前目标、验收标准、限制条件</td><td>解决“到底要改成什么样”</td></tr><tr><td>反馈上下文</td><td>测试结果、构建报错、审查意见</td><td>解决“刚才那次改动为什么失败”</td></tr></tbody></table><p>只有第一层时，模型更像“高级补全”。 同时拥有前三层时，才开始具备“辅助完成一个真实任务”的能力。</p><h2 id="_3-局部上下文够用的场景-其实比你想象中少" tabindex="-1">3. 局部上下文够用的场景，其实比你想象中少 <a class="header-anchor" href="#_3-局部上下文够用的场景-其实比你想象中少" aria-label="Permalink to &quot;3. 局部上下文够用的场景，其实比你想象中少&quot;">​</a></h2><p>局部上下文适合下面这些问题：</p><ul><li>补一段函数实现</li><li>修一处显眼的语法错误</li><li>写一个小测试用例</li><li>为已有函数补注释</li></ul><p>一旦任务变成下面这些，就很容易超出局部上下文能力：</p><ul><li>重构跨模块接口</li><li>找出某个异常的根因</li><li>修改一个影响多个实现的公共契约</li><li>按照团队已有模式新增功能</li></ul><p>这时继续“只喂当前文件”，往往会让模型把看似合理的局部改动放到错误的系统位置上。</p><h2 id="_4-仓库上下文如何被组织起来" tabindex="-1">4. 仓库上下文如何被组织起来 <a class="header-anchor" href="#_4-仓库上下文如何被组织起来" aria-label="Permalink to &quot;4. 仓库上下文如何被组织起来&quot;">​</a></h2><p>现代 AI 编程工具的能力差异，核心之一就在这里。一个更稳妥的上下文工程方案，通常会包含下面几步：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;代码仓&quot;] --&gt; B[&quot;解析项目结构&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;切分代码块&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;建立索引 / 向量化 / 符号关系&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;按任务检索相关代码&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;压缩与排序&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[&quot;组装为模型上下文&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[&quot;输出建议 / 修改方案&quot;]</span></span></code></pre></div><h3 id="_4-1-结构解析" tabindex="-1">4.1 结构解析 <a class="header-anchor" href="#_4-1-结构解析" aria-label="Permalink to &quot;4.1 结构解析&quot;">​</a></h3><p>第一步不是“把整个仓库扔给模型”，而是先理解项目结构：</p><ul><li>模块和包组织</li><li>构建文件</li><li>依赖关系</li><li>入口与配置</li></ul><p>这一步决定了后面的检索是否有方向感。</p><h3 id="_4-2-代码切分" tabindex="-1">4.2 代码切分 <a class="header-anchor" href="#_4-2-代码切分" aria-label="Permalink to &quot;4.2 代码切分&quot;">​</a></h3><p>代码切分不能只按固定长度，否则会破坏语义边界。更合理的粒度通常是：</p><ul><li>类</li><li>方法</li><li>配置块</li><li>测试用例</li></ul><p>当代码块能对应明确语义单元时，后续检索质量会明显更高。</p><h3 id="_4-3-检索与排序" tabindex="-1">4.3 检索与排序 <a class="header-anchor" href="#_4-3-检索与排序" aria-label="Permalink to &quot;4.3 检索与排序&quot;">​</a></h3><p>检索不是“多拿一点就更好”。在代码场景中，最重要的是相关性排序：</p><ul><li>当前符号定义</li><li>关键调用链</li><li>相关测试</li><li>构建或报错位置</li><li>团队范例实现</li></ul><p>如果把太多“略微相关”的代码一起塞进上下文，模型反而更容易失焦。</p><h2 id="_5-任务上下文-最容易被忽略的一层" tabindex="-1">5. 任务上下文：最容易被忽略的一层 <a class="header-anchor" href="#_5-任务上下文-最容易被忽略的一层" aria-label="Permalink to &quot;5. 任务上下文：最容易被忽略的一层&quot;">​</a></h2><p>即便仓库上下文足够完整，如果任务描述很模糊，结果仍然会漂。</p><p>不好的任务描述：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把这段代码重构得更优雅一些。</span></span></code></pre></div><p>更好的任务描述应该包含：</p><ul><li>目标：要解决什么问题</li><li>限制：不能改什么</li><li>交付物：希望输出什么</li><li>验收：以什么为准判定成功</li></ul><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请把这个 300 行方法拆成多个私有方法，但不要改变现有对外接口和返回结构。</span></span>
<span class="line"><span>优先减少分支嵌套，不引入新的设计模式。</span></span>
<span class="line"><span>输出时先给出重构计划，再给关键改动点，最后说明哪些测试需要补。</span></span></code></pre></div><p>在工程场景里，这样的约束比“写得更厉害一点”有用得多。</p><h2 id="_6-反馈上下文-真正让模型进入闭环" tabindex="-1">6. 反馈上下文：真正让模型进入闭环 <a class="header-anchor" href="#_6-反馈上下文-真正让模型进入闭环" aria-label="Permalink to &quot;6. 反馈上下文：真正让模型进入闭环&quot;">​</a></h2><p>很多团队会在第一次回答不理想后，重新开一个新会话继续问。这样做会损失最重要的上下文之一：<strong>失败反馈</strong>。</p><p>反馈上下文通常来自：</p><ul><li>编译错误</li><li>测试失败</li><li>Lint 结果</li><li>Code Review 意见</li><li>运行日志</li></ul><p>把这些反馈结构化地回喂给模型，效果通常比“重新描述一遍问题”更直接。</p><p>推荐做法是：</p><ol><li>先让模型给方案或改动</li><li>在本地执行构建或测试</li><li>把失败结果和关键代码片段回喂</li><li>要求它只针对失败点修正</li></ol><p>这比一开始追求“一次到位”更符合真实工程环境。</p><h2 id="_7-上下文压缩-不是塞满-而是保留决策需要的部分" tabindex="-1">7. 上下文压缩：不是塞满，而是保留决策需要的部分 <a class="header-anchor" href="#_7-上下文压缩-不是塞满-而是保留决策需要的部分" aria-label="Permalink to &quot;7. 上下文压缩：不是塞满，而是保留决策需要的部分&quot;">​</a></h2><p>上下文工程的核心不是尽可能多，而是尽可能有用。</p><p>常见压缩策略包括：</p><ul><li>保留接口定义，压缩实现细节</li><li>保留调用链关键节点，删除重复代码</li><li>保留错误堆栈和直接相关文件，删除外围噪声</li><li>把长日志先总结，再把摘要送入模型</li></ul><p>一个实用原则是：<strong>优先保留会影响决策的事实，压缩可推导的细节</strong>。</p><h2 id="_8-一个可执行的工作流" tabindex="-1">8. 一个可执行的工作流 <a class="header-anchor" href="#_8-一个可执行的工作流" aria-label="Permalink to &quot;8. 一个可执行的工作流&quot;">​</a></h2><p>如果你要让 AI 帮忙完成一次真实改动，可以按下面这个流程组织上下文：</p><table tabindex="0"><thead><tr><th>步骤</th><th>要给模型什么</th></tr></thead><tbody><tr><td>任务澄清</td><td>目标、限制、验收标准</td></tr><tr><td>结构摸底</td><td>模块说明、相关文件、关键调用链</td></tr><tr><td>方案讨论</td><td>当前实现问题、备选方案、约束</td></tr><tr><td>实施改动</td><td>相关代码块、需要保持兼容的接口</td></tr><tr><td>验证修复</td><td>构建报错、测试结果、审查意见</td></tr></tbody></table><p>这套流程比单次长 Prompt 更重要，因为它把“上下文”变成了一种可持续组织的信息流。</p><h2 id="_9-常见反模式" tabindex="-1">9. 常见反模式 <a class="header-anchor" href="#_9-常见反模式" aria-label="Permalink to &quot;9. 常见反模式&quot;">​</a></h2><h3 id="_9-1-把整个仓库直接塞进上下文" tabindex="-1">9.1 把整个仓库直接塞进上下文 <a class="header-anchor" href="#_9-1-把整个仓库直接塞进上下文" aria-label="Permalink to &quot;9.1 把整个仓库直接塞进上下文&quot;">​</a></h3><p>结果通常是成本飙升、噪声变大、质量并未同步提升。</p><h3 id="_9-2-只给报错-不给目标" tabindex="-1">9.2 只给报错，不给目标 <a class="header-anchor" href="#_9-2-只给报错-不给目标" aria-label="Permalink to &quot;9.2 只给报错，不给目标&quot;">​</a></h3><p>模型可能能修这个报错，但不知道你的真实意图，容易修出局部正确、整体错误的结果。</p><h3 id="_9-3-只给目标-不给约束" tabindex="-1">9.3 只给目标，不给约束 <a class="header-anchor" href="#_9-3-只给目标-不给约束" aria-label="Permalink to &quot;9.3 只给目标，不给约束&quot;">​</a></h3><p>这会导致模型自作主张引入新的模式、改动更多文件、甚至改变行为。</p><h3 id="_9-4-不保留失败反馈" tabindex="-1">9.4 不保留失败反馈 <a class="header-anchor" href="#_9-4-不保留失败反馈" aria-label="Permalink to &quot;9.4 不保留失败反馈&quot;">​</a></h3><p>没有测试和构建反馈，模型很难进入有效迭代。</p><h2 id="_10-小结" tabindex="-1">10. 小结 <a class="header-anchor" href="#_10-小结" aria-label="Permalink to &quot;10. 小结&quot;">​</a></h2><p>代码场景下，Prompt 的上限取决于上下文工程。真正有效的做法不是“想一句更厉害的话”，而是把任务信息、仓库信息和反馈信息分层组织起来，让模型在正确的上下文里工作。</p><p>当团队开始这样使用 AI 时，它就不再只是写几行代码的补全工具，而会逐步变成一个能参与真实开发流程的协作者。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://docs.cursor.com/context/codebase-indexing" target="_blank" rel="noreferrer">Cursor: Codebase indexing</a></li><li><a href="https://docs.github.com/en/copilot" target="_blank" rel="noreferrer">GitHub Copilot 文档</a></li><li><a href="https://www.jetbrains.com/help/ai-assistant/about-ai-assistant.html" target="_blank" rel="noreferrer">JetBrains AI Assistant 文档</a></li><li><a href="https://platform.openai.com/docs/guides/prompt-engineering" target="_blank" rel="noreferrer">OpenAI: Prompt engineering</a></li><li>延伸阅读：<a href="./daily-efficiency.html">日常开发提效方案实战</a></li></ul>`,74)])])}const b=t(s,[["render",r]]);export{u as __pageData,b as default};
